function report = runT3OptimizationBenchmark(options)
%RUNT3OPTIMIZATIONBENCHMARK Gate dense exact-transport spin-2 T3.
%
% The expanded-patch CPU-double path remains the numerical reference. The
% benchmark separately reports optimized double equivalence and optimized
% single result-level precision behavior over the complete rendered scene.
%
% Traceability: algo/main.tex Eqs. (22), (25), and (58), Algorithm 1;
% implementation plan Stage C6.

arguments
    options.ImageSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [96, 112]
    options.LabelCount (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeGreaterThanOrEqual( ...
        options.LabelCount, 3)} = 33
    options.HeightRangeMetres (1, 2) double ...
        {mustBeFinite, mustBeIncreasing} = [-50, 50]
    options.TileSize (1, 2) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = [48, 56]
    options.LabelBlockSize (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBePositive} = 4
    options.TextureSeed (1, 1) double ...
        {mustBeFinite, mustBeInteger, mustBeNonnegative} = 71
    options.OutputFile (1, 1) string = ""
end

renderer = SyntheticPinholeRenderer( ...
    "t3-optimization", options.ImageSize, Supersample=2, ...
    PsfSigmaPixels=0.5, TextureSeed=options.TextureSeed);
pair = renderer.renderPair;
levels = 2 ^ renderer.BitDepth - 1;
g = HeightSweepGeometry( ...
    renderer.ReferenceCamera, renderer.MovingCamera);
r64 = double(pair.ReferenceImage) ./ levels;
m64 = double(pair.MovingImage) ./ levels;
r32 = single(pair.ReferenceImage) ./ single(levels);
m32 = single(pair.MovingImage) ./ single(levels);
c64 = HeightCostCurve(g, r64, m64, ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    WorkingPrecision="double");
c32 = HeightCostCurve(g, r32, m32, ...
    DerivativeSigma=1, IntegrationSigma=1, ...
    ReferenceValid=pair.ReferenceValid, MovingValid=pair.MovingValid, ...
    WorkingPrecision="single");
d64 = DenseHeightSweep(c64);
d32 = DenseHeightSweep(c32);
z = linspace(options.HeightRangeMetres(1), ...
    options.HeightRangeMetres(2), options.LabelCount);
products = ["LabelIndex", "BestCost", "Margin", ...
    "Confidence", "Support", "Correspondence", "Observability"];

reference = d64.runTiled(z, ...
    Channel="Spin2T3", Channels="Spin2T3", ...
    TileSize=options.TileSize, ...
    LabelBlockSize=options.LabelBlockSize, ...
    StoreCostVolumes=true, UseParallel=false);
optimizedDouble = d64.runT3Optimized(z, ...
    TileSize=options.TileSize, ...
    LabelBlockSize=options.LabelBlockSize, ...
    StoreCostVolumes=true, UseParallel=false, ...
    WorkingPrecision="double", Products=products);
doubleComparison = HeightSweepEquivalence.compare( ...
    reference.CostVolume, optimizedDouble.CostVolume, ...
    CostTolerance=1e-10, TieTolerance=1e-9);
optimizedSingle = d32.runT3Optimized(z, ...
    TileSize=options.TileSize, ...
    LabelBlockSize=options.LabelBlockSize, ...
    StoreCostVolumes=true, UseParallel=false, ...
    WorkingPrecision="single", Products=products);
singleComparison = HeightSweepEquivalence.comparePrecision( ...
    optimizedDouble, optimizedSingle);
joint = isfinite(optimizedDouble.CostVolume) ...
    & isfinite(optimizedSingle.CostVolume);
singleDelta = abs(double(optimizedDouble.CostVolume(joint)) ...
    - double(optimizedSingle.CostVolume(joint)));
if isempty(singleDelta)
    maximumSingleCostDelta = 0;
else
    maximumSingleCostDelta = max(singleDelta);
end
doubleSeconds = optimizedDouble.Runtime.EvaluationSeconds;
singleSeconds = optimizedSingle.Runtime.EvaluationSeconds;
referenceSeconds = reference.Runtime.EvaluationSeconds;
report = struct( ...
    "ImageSize", options.ImageSize, ...
    "HeightLabelsMetres", z, ...
    "ReferenceSeconds", referenceSeconds, ...
    "OptimizedDoubleSeconds", doubleSeconds, ...
    "OptimizedSingleSeconds", singleSeconds, ...
    "DoubleSpeedup", referenceSeconds ./ doubleSeconds, ...
    "SingleSpeedup", referenceSeconds ./ singleSeconds, ...
    "DoubleComparison", doubleComparison, ...
    "SingleComparison", singleComparison, ...
    "MaximumSingleCostDelta", maximumSingleCostDelta, ...
    "ReferenceOutputArrayBytes", ...
    reference.Runtime.OutputArrayBytes, ...
    "OptimizedDoubleOutputArrayBytes", ...
    optimizedDouble.Runtime.OutputArrayBytes, ...
    "OptimizedSingleOutputArrayBytes", ...
    optimizedSingle.Runtime.OutputArrayBytes, ...
    "GeometryPrecision", "double", ...
    "OptimizedPrecisions", ["double", "single"], ...
    "Transport", "exact local A^T at every halo sample", ...
    "ChannelStatus", "diagnostic-only", ...
    "AllPass", doubleComparison.Pass && singleComparison.Pass, ...
    "PixelConvention", ...
    "one-based [x,y]=[column,row] pixel centers", ...
    "WorldFrame", "local ENU metres", ...
    "ElevationDatum", "local synthetic ENU Z=0");

fprintf("Dense T3: reference %.3f s, optimized double %.3f s " ...
    + "(%.3fx), single %.3f s (%.3fx)\n", ...
    referenceSeconds, doubleSeconds, report.DoubleSpeedup, ...
    singleSeconds, report.SingleSpeedup);
fprintf("  double max drift %.3e; single max drift %.3e; " ...
    + "stable single disagreements %d; pass %s\n", ...
    doubleComparison.MaximumAbsoluteCostDifference, ...
    maximumSingleCostDelta, ...
    singleComparison.StableLabelDisagreementCount, ...
    string(report.AllPass));
fprintf("  output payload reference %.3f MiB, optimized double %.3f MiB, " ...
    + "single %.3f MiB\n", ...
    report.ReferenceOutputArrayBytes ./ 2 ^ 20, ...
    report.OptimizedDoubleOutputArrayBytes ./ 2 ^ 20, ...
    report.OptimizedSingleOutputArrayBytes ./ 2 ^ 20);
if options.OutputFile ~= ""
    save(options.OutputFile, "report", "-v7.3");
end
end

function mustBeIncreasing(x)
if x(2) <= x(1)
    error("runT3OptimizationBenchmark:HeightRangeNotIncreasing", ...
        "HeightRangeMetres must be strictly increasing.");
end
end
